local redis = require "resty.redis"
local cjson = require "cjson"

local function safe_redis_command(command, args)
    -- Whitelist of allowed commands
    local allowed_commands = {
        ["get"] = true,
        ["set"] = true,
        ["del"] = true,
        ["exists"] = true,
        ["hget"] = true,
        ["hset"] = true,
        ["hdel"] = true,
        ["lpush"] = true,
        ["lpop"] = true,
        ["sadd"] = true,
        ["srem"] = true,
        ["scard"] = true,
        ["zadd"] = true,
        ["zrem"] = true,
        ["zcard"] = true,
        ["incr"] = true,
        ["decr"] = true,
        ["expire"] = true,
        ["ttl"] = true
    }
    
    -- Validate command
    if not allowed_commands[string.lower(command)] then
        return nil, "Command not allowed"
    end
    
    -- Build safe command string
    local cmd_parts = {string.upper(command)}
    for _, arg in ipairs(args) do
        -- Escape special characters and validate
        if type(arg) == "string" then
            arg = string.gsub(arg, "[\"\\$]", "\\%1")
        end
        table.insert(cmd_parts, tostring(arg))
    end
    
    return table.concat(cmd_parts, " ")
end

local function execute_redis_command(cmd_string)
    local red = redis:new()
    red:set_timeout(1000) -- 1 second timeout
    
    local ok, err = red:connect("127.0.0.1", 6379)
    if not ok then
        return nil, "Failed to connect to Redis: " .. err
    end
    
    local res, err = red:eval(cmd_string, 0, "")
    if not res then
        return nil, "Redis command failed: " .. err
    end
    
    red:close()
    return res
end

